-- virtual_wallets migration generated from CSV
-- Run on VPS: psql -U postgres -d errandwork -f virtual_wallets_migration.sql

CREATE TABLE IF NOT EXISTS virtual_wallets (
  id VARCHAR(255) PRIMARY KEY,
  user_id VARCHAR(255),
  is_active BOOLEAN DEFAULT TRUE,
  balance NUMERIC(12,2) DEFAULT 0,
  escrow NUMERIC(12,2) DEFAULT 0,
  total_earned NUMERIC(12,2) DEFAULT 0,
  total_spent NUMERIC(12,2) DEFAULT 0,
  requires_funding BOOLEAN DEFAULT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Clear existing data to avoid duplicates
TRUNCATE TABLE virtual_wallets;

